# Weapon Forge
import random

class Material:
    def __init__(self, name, strength):
        self.name = name
        self.strength = strength

class Weapon:
    def __init__(self, name, material):
        self.name = name
        self.material = material
        self.enchant = None
        self.durability = 100

    def apply_enchant(self, spell):
        self.enchant = spell
        self.durability -= 10

    def repair(self):
        self.durability = 100

class Forge:
    def __init__(self):
        self.fuel = 100
        self.queue = []

    def smelt(self, material):
        self.fuel -= 20
        return material.strength * 2

    def craft(self, name, material):
        power = self.smelt(material)
        weapon = Weapon(name, material)
        return weapon

    def batch_craft(self, orders):
        results = []
        for name, mat in orders:
            w = self.craft(name, mat)
            results.append(w)
        return results
